"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[1862],{91862:(e,t,a)=>{a.r(t),a.d(t,{search:()=>s});let n=new(a(61860)).Ay.Document({tokenize:"full",document:{id:"url",index:"content",store:["title","pageTitle"]},context:{resolution:9,depth:2,bidirectional:!0}});for(let{url:e,sections:t}of[{url:"/",sections:[["API Documentation",null,["WorkOrder Systems OSS aims to be the Linux of maintenance software: a production-grade, self-hostable core you can deploy and extend without vendor lock-in. This site documents the Supabase-backed public API—reads through views, writes through RPCs—wrapped by @workorder-systems/sdk for tenants, work orders, assets, labor, reporting, and the rest of the domain. The project vision and adoption notes live in docs/PROJECT.md. ","Quickstart","Installation"]],["Getting started ","getting-started",["Copy your project URL and anon key from the dashboard → Project Settings → API.","Install @workorder-systems/sdk and @supabase/supabase-js, then call createDbClient(url, anonKey).","Sign users in with Supabase Auth. For tenant-scoped data, set tenant context and refresh the session so the JWT includes tenant_id."]]]},{url:"/agents",sections:[["Building agents and MCP clients",null,["If you are building an AI assistant, workflow agent, or MCP client on top of this CMMS, treat the public API surface the same way you would treat a human-facing SDK contract: explicit tenant flow, explicit search/disambiguation, retry-safe writes, and machine-readable errors. "]],["Recommended flow","recommended-flow",["For the common “search, then create work order” automation path, use this order:","Key rules:","Do not guess tenant context.","Do not guess entity ids when multiple candidates are plausible.","Always use an idempotency key for automation-driven creates.","Prefer summary reads first to reduce token usage."]],["Tenant bootstrap","tenant-bootstrap",["Tenant-scoped views and many RPCs depend on tenant_id being present in the JWT. The safest flow is:","authenticate the user","resolve which tenant to use","call rpc_set_tenant_context(...) or client.setTenant(tenantId)","refresh the session so the next JWT includes tenant_id","For HTTP MCP, the server can refresh in-request when the client sends X-Supabase-Refresh-Token. Without a refresh, tenant-scoped reads may return empty results because the old JWT still lacks tenant_id."]],["Search and disambiguation","search-and-disambiguation",["Use search before writes when the user refers to an asset, part, or location by natural language. The richer search surface returns:","canonical entity_id","entity_type","label","ranking fields such as match_type and score","disambiguation hints such as:","site_name","location_path","asset_number","barcode","part_number","supplier_name","disambiguation_hint","That lets agents ask a user:","“Did you mean pump P-101 in Plant A > Utilities, or pump P-101 in Plant B > Chilled Water?”","instead of guessing."]],["Retry-safe writes","retry-safe-writes",["Programmatic work-order creation supports an optional client request id.","Reuse the same id when retrying the same intended create. If the first attempt already succeeded, the API returns the original work_order_id instead of creating a duplicate.","Use a fresh request id only when the user intends a different work order."]],["Structured errors","structured-errors",["SDK calls throw SdkError with:","message","code","details","hint","MCP tools preserve the same structure in their JSON error payloads so agents can branch on:","tenant context required","permission denied","validation error","retryable / transient cases","Prefer handling errors by code and then using message/details/hint for user-facing explanations."]],["Embed search and freshness","embed-search-and-freshness",["When WORKORDER_SYSTEMS_EMBED_SEARCH_URL is configured, MCP exposes text-in similarity tools such as:","similar_past_work_orders","semantic_search","These depend on separately indexed embeddings. Treat them as assistive grounding, not as a source of truth for canonical ids:","use embed search to find similar history","use entity search / canonical ids for the final write","Index freshness depends on your embedding/indexing pipeline. If a very new work order, asset, or part is not appearing in similarity results yet, fall back to standard list/get/search surfaces.","MCP overview","Tenant context","Errors","Work orders"]]]},{url:"/analytics",sections:[["Analytics reporting layer",null,["Use the read-only reporting schema for BI tools and data warehouse export. Dimension and fact views, plus KPI views (MTTR, MTBF, PM compliance, utilization, backlog). All views are tenant-scoped: set tenant context before you query. "]],["Overview","overview",["The reporting layer gives you:","Dimension views: tenant, location (with site), department, asset (with site), and a date dimension table for time slicing","Fact views: work orders, labor (time entries), parts, downtime/incidents (reactive completed WOs), PM compliance","KPI views: MTTR, MTBF, PM compliance %, technician utilization %, backlog (open/overdue counts)","Every view filters by the current tenant via authz.get_current_tenant_id(). No cross-tenant data is exposed. You can slice by site_id, department_id, and date columns in your BI tool by filtering or grouping on the fact/dimension columns.","This doc covers data structures and access only; building dashboards or UI is out of scope."]],["Set tenant context before querying","set-tenant-context-before-querying",["BI and warehouse clients must run with the current tenant set so get_current_tenant_id() returns the right tenant.","Authenticate as a user who is a member of the tenant.","Call rpc_set_tenant_context(tenant_id) (or the SDK: client.setTenant(tenantId)).","Optionally refresh the JWT so the token carries the tenant; then all later requests use that tenant.","Query the reporting views; they return only that tenant's data.","Always set tenant context first so BI and exports only see the intended tenant."]],["Reporting objects","reporting-objects",["All objects live in the reporting schema. Views are real-time; the only table with persisted data is dim_time (pre-populated date dimension).","| Object | Kind | Grain / purpose |\n|--------|------|------------------|\n| reporting.dim_tenant | view | One row per tenant (current context only). |\n| reporting.dim_location | view | One row per location; includes site_id, site_name. |\n| reporting.dim_department | view | One row per department. |\n| reporting.dim_asset | view | One row per asset; includes site_id via location. |\n| reporting.dim_time | table | One row per date (bounded range); year, quarter, month, week, day_of_week, is_weekend, year_month, year_week. |\n| reporting.fact_work_orders | view | One row per work order; measures: duration_hours, total_labor_minutes, total_*_cost_cents; dims: location_id, asset_id, department_id, site_id, created_date, completed_date, status, priority, maintenance_type. |\n| reporting.fact_labor | view | One row per time entry; measures: minutes, labor_cost_cents; dims: work_order_id, technician_id, entry_date, site_id, etc. |\n| reporting.fact_parts | view | One row per work order part line; measures: quantity, unit_cost_cents, total_cost_cents; dims: work_order_id, entry_date, site_id. |\n| reporting.fact_downtime_incidents | view | One row per incident (reactive, completed WO); measures: duration_hours, total_labor_minutes; for MTBF. |\n| reporting.fact_pm_compliance | view | One row per PM execution; on_time (within 7 days of scheduled_date), actual_hours, cost; dims: asset_id, site_id. |\n| reporting.kpi_mttr | view | MTTR by tenant, site, asset, department, month (last 365 days). |\n| reporting.kpi_mtbf | view | MTBF per asset/site from fact_downtime_incidents. |\n| reporting.kpi_pm_compliance | view | PM on-time % by tenant, site, asset, month. |\n| reporting.kpi_utilization | view | Technician utilization % (actual / scheduled minutes) by technician and day. |\n| reporting.kpi_backlog | view | Open and overdue counts by tenant, site, department, priority. |","Views reflect live data. The only materialized data is reporting.dim_time (static). Other analytics materialized views (e.g. public.mv_work_order_summary) are refreshed via public.refresh_analytics_views() and live outside the reporting schema."]],["Slicing (site, department, time)","slicing-site-department-time",["Tenant: One tenant per session; set via rpc_set_tenant_context(tenant_id) (or SDK). All reporting views already filter to that tenant.","Site: Use site_id (and optionally site_name from dimensions). Facts expose site_id; filter or group by it in BI (e.g. WHERE site_id = $id or “Group by site_id”).","Department: Use department_id on facts or reporting.dim_department. Filter or group by department_id in BI.","Time: Use created_date, completed_date, or entry_date on facts, or join to reporting.dim_time on date for year/quarter/month/week. KPI views expose period_month or period_date where applicable.","All slicing stays within the current tenant."]],["Export patterns","export-patterns",["Full export (current tenant): Set tenant context, then run e.g. SELECT * FROM reporting.fact_work_orders (and similarly for other facts/dimensions). Export to your warehouse or file.","Incremental export: Use updated_at or completed_date / created_date if you mirror the data; reporting views don't add an export watermark. For date-bounded exports, filter on the fact’s date columns (e.g. completed_date >= $last_run).","BI tools: Point your tool at the Postgres (or Supabase) connection, set tenant (e.g. via a parameter that drives rpc_set_tenant_context), then query reporting.* views. Use reporting.get_analytics_metadata() for discovery (see below)."]],["Discovery","discovery",["Call this RPC to list reporting objects and their descriptions for BI discovery:","Call it after setting tenant context if your client uses the same session for metadata and data."]],["Next steps","next-steps",["Tenant context: set and clear tenant context","Work orders: work order API reference"]]]},{url:"/asset-downtime",sections:[["Asset downtime",null,["Downtime events are append-friendly facts: which asset stopped producing value, why, when it started and (optionally) ended, and optional link to a work order. They are low ceremony to implement and unlock availability and reliability metrics that feed dashboards and future automation cleanly. "]],["Why record downtime","why-record-downtime",["Gives a canonical timeline per asset (open vs closed intervals).","Correlates outages with corrective work via linked_work_order_id.","Aggregates in the reporting schema for monthly rollups (BI / warehouse)."]],["Permissions","permissions",["| Permission | Purpose |\n|------------|---------|\n| downtime.record | Insert events via RPC |\n| downtime.view | Read events (direct table access in app; typical apps use reporting views or service-side queries) |","Tenant admin includes these by default."]],["Record an event","record-an-event",[]],["Reason keys","reason-keys",["Each tenant has rows in cfg.downtime_reasons. New tenants get defaults, including:","breakdown","planned_maintenance","no_demand","other","Keys must match ^[a-z0-9_]+$. Configure additional reasons per tenant in your admin UI (insert/update on cfg.downtime_reasons with appropriate RLS — catalog is tenant-scoped)."]],["Reporting schema","reporting-schema",["Monthly aggregates are exposed in reporting.v_asset_downtime_monthly (PostgREST reporting schema in this project). The generated SDK Database type currently covers public only; use client.supabase with a second client or schema option if you query reporting from the app, or consume that view from BI tools.","Assets","Analytics reporting"]]]},{url:"/assets",sections:[["Assets",null,["Lists and gets assets for the current tenant; create, update, delete. Set tenant context before calling these methods. ","Downtime / availability: use client.assets.recordDowntime() for structured outage events — see Asset downtime.","Barcodes / QR payloads: optional barcode on create/update and client.assets.resolveByScanCode() — see Floor ops and scanning."]],["List assets","list-assets",["List all assets for the current tenant (from v_assets)."]],["Get by ID","get-by-id",["Fetch a single asset by ID."]],["Lifecycle fields","lifecycle-fields",["AssetRow includes lifecycle and planning fields (from v_assets). Use them for reporting and replacement planning; create/update asset RPCs may not yet accept all of these (set via database or future API):","commissioned_at – when the asset was placed into service","end_of_life_estimate – estimated EOL date for replacement planning","decommissioned_at – when the asset was decommissioned","replaced_by_asset_id – asset that replaced this one (this asset retired)","replacement_of_asset_id – asset that this one replaced","warranty_expires_at – warranty expiration date","service_contract_expires_at – service/maintenance contract expiration","planned_replacement_date – planned replacement date for capital planning","For alerts (e.g. warranty or EOL approaching), use client.costs.listLifecycleAlerts() or client.costs.assetLifecycleAlerts(). See Costs & lifecycle."]],["Warranties (multi-row)","warranties-multi-row",["warranty_expires_at above is a rollup from active app.asset_warranties rows. Use v_asset_warranties for full history and multiple policies.","More context: Capability inventory — Warranty."]],["Barcode and scan resolution","barcode-and-scan-resolution",["Optional barcode (unique per tenant when set) is separate from assetNumber. After a scan, call client.assets.resolveByScanCode(tenantId, text) (or rpc_resolve_asset_by_scan_code) to get an asset id: matches barcode first, then asset_number. See Floor ops and scanning."]],["Create asset","create-asset",["Create a new asset. Returns the new asset UUID.","Required. Tenant UUID.","Required. Asset display name.","Optional. Description.","Optional. Asset number or code.","Optional. Scannable id (unique per tenant when set). See Floor ops and scanning.","Optional. Location UUID.","Optional. Department UUID.","Optional. Default active. Status key."]],["Update asset","update-asset",["Update an existing asset. All fields except tenantId and assetId are optional."]],["Delete asset","delete-asset",["Delete an asset by tenant and asset ID.","Work orders","Costs & lifecycle","Locations"]]]},{url:"/audit",sections:[["Audit",null,["Read audit logs for entity changes and permission changes, and inspect audit retention configuration per tenant. Set tenant context before calling these methods. "]],["Entity changes","entity-changes",["List entity changes for the current tenant."]],["Permission changes","permission-changes",["List permission changes (e.g. role assignments, scope changes) for the current tenant."]],["Retention configuration","retention-configuration",["Read audit retention configuration."]]]},{url:"/authentication",sections:[["Authentication",null,["The SDK uses Supabase Auth. There is no separate API-key header per request: the active session’s JWT is sent automatically. "]],["How it works","how-it-works",["Client: Built with the project URL and anon key. The anon key is public by design; RLS and RPC checks enforce what each user can do.","Session: Users sign in with client.supabase.auth (password, OAuth, magic link, etc.). All client.tenants, client.workOrders, and other resources share that same client and session."]],["Sign in","sign-in",["Use your URL and anon key from Project Settings → API:","After sign-in, Supabase stores the session (default: browser storage, or whatever you configured). Later calls to client.workOrders.list() and the rest use that session automatically."]],["Using the SDK","using-the-sdk",["You do not attach a bearer token manually. Once client.supabase.auth has a session, resource methods run as that user.","For tenant-scoped data, also call client.setTenant(tenantId) and refresh the session so the JWT carries tenant_id. See Tenant context."]],["Next steps","next-steps",["Tenant context","Quickstart"]]]},{url:"/authorization",sections:[["Authorization (RBAC & ABAC)",null,["The Work Order Systems API uses RBAC (role-based access control) and ABAC (attribute-based access control) on top of tenant isolation. RLS enforces tenant membership; permissions gate what you can do; scopes gate where you can do it (e.g. by location or department). The SDK exposes client.authorization helpers for working with permissions, roles, and scopes. "]],["Overview","overview",["Tenant isolation: RLS ensures you only see and change data for tenants you are a member of. Tenant context (setTenant) tells the backend which tenant you are acting in.","RBAC: Each tenant has roles (e.g. admin, member, technician, manager). Roles have permissions (e.g. tenant.admin, workorder.edit, workorder.assign). Users are assigned roles per tenant.","ABAC: Users can have scopes (location or department). Some operations require not only a permission but also a scope (e.g. “can edit work orders in this location”). Scopes are stored in app.membership_scopes and checked by RPCs via authz.check_abac_scope.","Permissions are enforced inside RPCs (e.g. authz.validate_permission). The SDK exposes a dedicated authorization resource (client.authorization) for permission, role, and scope operations; you can still use the raw Supabase client for advanced queries when needed."]],["RBAC: roles and permissions","rbac-roles-and-permissions",["Roles are per-tenant (cfg.tenant_roles). New tenants get default roles: admin, member, technician, manager.","Permissions are global (cfg.permissions). Tenants assign permissions to their roles via cfg.tenant_role_permissions.","User–role assignment is per tenant: app.user_tenant_roles. You assign roles with client.tenants.assignRole() and invite users with client.tenants.inviteUser() (see Tenants).","To assign a permission to a role (e.g. give member the workorder.create permission), use the SDK helper. Requires tenant.admin permission.","Common permission keys include tenant.admin, workorder.create, workorder.edit, workorder.assign, workorder.complete.assigned, asset.edit, and others defined in the permission catalog. List role–permission mappings via the v_role_permissions view (and v_permissions for the catalog)."]],["Checking permissions","checking-permissions",["To check whether the current user has a permission in the current tenant, call client.authorization.hasPermission. Set tenant context first.","To list all permission keys the current user has in the tenant, use client.authorization.getUserPermissions:","Use these to drive UI (e.g. show/hide “Edit” or “Assign”) or to decide whether to call an RPC. The backend still enforces permissions inside each RPC; client-side checks are for UX only."]],["ABAC: scopes","abac-scopes",["Scopes restrict access by location or department. For example, a user might be allowed to edit work orders only in a specific location. Scopes are stored in app.membership_scopes and checked by RPCs via authz.check_abac_scope (and helpers like authz.has_location_scope, authz.has_department_scope).","To grant a scope to a user (e.g. “can act in this location”), use client.authorization.grantScope. Requires tenant.admin permission.","To revoke a scope, use client.authorization.revokeScope:","Scope types are typically location or department; p_scope_value is the UUID of the location or department. Which RPCs use scopes (and how) is defined per operation (e.g. “edit work order in this location” may require both workorder.edit and the corresponding location scope)."]],["How RPCs enforce access","how-rpcs-enforce-access",["RLS on tenant-scoped tables ensures only tenant members can read/write; views and RPCs run with the caller’s identity.","Permissions: Write RPCs call authz.validate_permission(user_id, tenant_id, permission_key). If the user lacks the permission, the RPC returns an error (e.g. 42501 with a message like “Permission denied … tenant.admin required”).","Scopes: RPCs that are scope-aware call authz.check_abac_scope (or helpers) to ensure the user has the required location/department scope before allowing the operation.","Workflow transitions: Status transitions can have a required_permission (and optional guard). The workflow engine checks the user’s permissions before allowing the transition (e.g. draft → assigned may require workorder.assign).","So: RLS = tenant boundary; RBAC = what you’re allowed to do; ABAC = where you’re allowed to do it (when the RPC enforces scopes).","Tenants (assign roles, invite users)","Errors (permission denied)"]]]},{url:"/capability-inventory",sections:[["Capability inventory",null,["This page answers “is that in the platform?” for areas that are easy to confuse with gaps. The schema is authoritative; SDK and docs catch up over time — use client.supabase for any typed RPC/view not yet wrapped on client.* (most domains have a client.* resource). "]],["Vendors and contractors","vendors-and-contractors",["In the database: app.suppliers is the vendor/contractor master (parts vendor, labor contractor, or both). Columns include supplies_parts, supplies_labor, tax_id, insurance_expires_at. Work orders link a primary contractor via primary_supplier_id; vendor cost lines use work_order_vendor_costs.supplier_id with RPCs such as rpc_upsert_work_order_vendor_cost.","Not a separate “contractor” table — contractors are suppliers flagged for labor. SDK: use client.partsInventory for suppliers/parts flows where wrapped; otherwise client.supabase.rpc.","See also Parts & inventory."]],["Warranty tracking","warranty-tracking",["In the database: app.asset_warranties holds multiple warranty rows per asset (supplier link, type, dates, coverage). A trigger keeps assets.warranty_expires_at aligned with the max active expires_on. rpc_upsert_asset_warranty creates/updates rows; public.v_asset_warranties lists them for the tenant.","Not “only a single column” — the column is a rollup for quick filters and lifecycle alerts; the table is the source of truth.","SDK: client.assets.listWarranties(), client.assets.upsertWarranty(). Lifecycle rollups remain on client.costs (alerts / TCO)."]],["Documents and attachments","documents-and-attachments",["In the database: Files use Storage plus app.entity_attachments (and triggers). cfg.document_types catalogs document kinds; attachment tables carry document_type_key, is_controlled, effective_date, revision_label (lightweight metadata — not a full QMS revision graph).","Gap vs strict “controlled document” systems: no automatic revision chains, approvals, or obsolescence workflow in-app — you model discipline in revision_label / process, or extend later.","See Work orders → Attachments and migration cmms_core_docs_tools_handover."]],["Barcodes and scan resolution","barcodes-and-scan-resolution",["In the database: optional barcode on app.assets and app.parts (unique per tenant when set), plus rpc_resolve_asset_by_scan_code and rpc_resolve_part_by_scan_code (match barcode, then asset_number / part_number / external_id for parts). Exposed on v_assets, v_parts, v_parts_with_stock, v_mobile_assets.","SDK: client.assets (barcode on create/update, resolveByScanCode), client.partsInventory (barcode on create/update, resolvePartByScanCode).","QR / camera UI is your app or design system (e.g. @workspace/ui); the API stores and resolves the payload string. See Floor ops and scanning."]],["Tools and equipment","tools-and-equipment",["In the database: app.tools and app.tool_checkouts with public.v_tools, v_tool_checkouts, rpc_checkout_tool, rpc_return_tool.","API: rpc_create_tool and rpc_update_tool with tool.manage; list via v_tools. Checkout requires tool.status = 'available'.","SDK: client.fieldOps.createTool, updateTool, lists, checkout/return. See Field operations."]],["Shift handover / logbook","shift-handover-logbook",["In the database: app.shift_handovers and related RPCs (rpc_create_shift_handover, rpc_submit_shift_handover, rpc_acknowledge_shift_handover, rpc_add_shift_handover_item), plus public.v_shift_handovers.","SDK: client.fieldOps (create/submit/ack/item + list view)."]],["Work order labor assignment","work-order-labor-assignment",["Internal technicians: assigned_to on the work order (auth user) plus the labor module (crews, assignments, scheduling). External labor: primary_supplier_id and vendor cost lines, not a second “assign to supplier user” field — external identity is out-of-band unless you add integration.","Field operations","Assets"]]]},{url:"/catalogs",sections:[["Catalogs",null,["Manage status, priority, and maintenance type catalogs per tenant. These catalogs power workflows and dashboards. Set tenant context before calling these methods. "]],["List catalogs","list-catalogs",["List catalogs for the current tenant."]],["Create status","create-status",["Create a status for an entity type (e.g. work order). Requires tenant.admin. Returns the status key."]],["Create status transition","create-status-transition",["Create an allowed transition between two statuses. Requires tenant.admin. Returns the transition ID."]],["Create priority","create-priority",["Create a priority definition. Requires tenant.admin. Returns the priority key."]],["Create maintenance type","create-maintenance-type",["Create a maintenance type. Requires tenant.admin. Returns the maintenance type key."]],["Get workflow graph","get-workflow-graph",["Fetch the workflow graph for an entity type as JSON. This is useful for building UI around allowed status transitions."]]]},{url:"/configuration",sections:[["Configuration",null,["Where you run code (your app, CI, or a script), you supply the Supabase URL and keys yourself. Deployed Edge Functions are different: Supabase injects every variable whose name starts with SUPABASE_; you never set those as custom secrets. ","See the repo .env.example for names used in this project."]],["SDK and CI","sdk-and-ci",["Point createDbClient, tests, and scripts at your project using values from Project Settings → API in the Supabase dashboard. Do not commit real keys.","Project API URL (cloud https://…supabase.co or local http://127.0.0.1:54321).","Anon JWT. Safe for clients; RLS still applies.","Service-role JWT. Bypasses RLS. Use only in trusted environments (e.g. CI setup or admin tools)."]],["Edge Functions","edge-functions",["Built-in SUPABASE_* variables","On Supabase-hosted functions, the runtime provides SUPABASE_URL, SUPABASE_ANON_KEY, SUPABASE_SERVICE_ROLE_KEY, and any other reserved SUPABASE_* names for your project. Read them with Deno.env.get(...) as usual.","You cannot create dashboard secrets or supabase secrets set entries that start with SUPABASE_. Those prefixes are reserved. Nothing to configure for them in production.","Your own secrets","Only use Edge Functions → Secrets or supabase secrets set for names that do not start with SUPABASE_ (feature flags, third-party API keys, and so on).","ingest-meter-reading","Relies on the injected SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY for service-role access. No manual SUPABASE_* setup."]],["Local development","local-development",["From the repo root: pnpm start or pnpm supabase:start (Supabase CLI project in apps/supabase).","After migrations: pnpm gen-types so the SDK matches the database.","pnpm supabase:functions (or cd apps/supabase && supabase functions serve …) exposes the same built-in SUPABASE_* names locally; anything else your function needs goes in your env file or CLI flags. See local Edge Functions."]],["Tests","tests",["pnpm test and pnpm test:ci read SUPABASE_URL, SUPABASE_ANON_KEY, and when needed SUPABASE_SERVICE_ROLE_KEY from the environment (same as the SDK table above). Details: tests/README.md in the repo.","Installation"]]]},{url:"/costs",sections:[["Costs & lifecycle",null,["Work order costs (labor, parts, vendor), roll-ups by asset, location, department, and project, asset lifecycle alerts (warranty, EOL, contract, replacement), and total cost of ownership. Set tenant context before calling these methods. "]],["Overview","overview",["The client.costs resource and client.projects support:","Work order costs – labor (from time entries), parts, and vendor costs per work order","Cost roll-ups – by asset, location, department, or project (views and RPC with optional date filter)","Lifecycle alerts – assets with warranty, end-of-life, contract, or planned replacement due within a window","Asset TCO – total cost of ownership for a single asset (optional date range)","Projects – list/get via client.projects; create, update, delete via client.projects.create / update / delete on the Projects page (project.manage); use projectId on work orders for roll-up","Labor cost comes from work_order_time_entries (e.g. labor_cost_cents). Parts and vendor costs are stored in work_order_parts and work_order_vendor_costs (see database migrations)."]],["Work order costs","work-order-costs",["Per-work-order cost totals (labor, parts, vendor, total). All amounts are in cents."]],["Cost roll-ups","cost-roll-ups",["Pre-aggregated costs by dimension (current tenant only)."]],["Cost rollup RPC","cost-rollup-rpc",["Roll-up by dimension with optional date filter on work order completed_at. Use when you need a single API that supports date ranges.","Required. Tenant UUID.","Required. One of: asset, location, department, project.","Optional. Filter work orders by completed_at on or after this date (ISO date string).","Optional. Filter work orders by completed_at on or before this date (ISO date string)."]],["Asset lifecycle alerts","asset-lifecycle-alerts",["Assets with upcoming lifecycle events: warranty expiring, end-of-life approaching, service contract expiring, or planned replacement due. The view shows events within the next 365 days; the RPC lets you set the window."]],["Asset total cost of ownership","asset-total-cost-of-ownership",["Total cost (labor + parts + vendor) and work order count for a single asset, with optional date filter on work order completed_at."]],["Projects","projects",["Projects group work orders for cost roll-up. From this app you typically read roll-ups with client.costs.listProjectCosts() or client.costs.costRollup({ groupBy: 'project', ... }).","CRUD on project rows (not read-only): use client.projects — see Projects → Create project for client.projects.create, plus update and delete on the same page. That requires project.manage.","When creating a work order, pass projectId so its costs appear in project roll-ups.","Projects","Assets (lifecycle fields)","Work orders","Dashboard"]]]},{url:"/dashboard",sections:[["Dashboard and summaries",null,["Read dashboard metrics, MTTR, open/overdue work orders, grouped metrics, and summary views. These are read-only views for analytics and reporting. Set tenant context before calling these methods. "]],["Dashboard metrics","dashboard-metrics",["Get the main dashboard metrics and MTTR metrics for the current tenant."]],["Open and overdue work orders","open-and-overdue-work-orders",["List open and overdue work orders as seen on the dashboard."]],["Work orders by status and maintenance type","work-orders-by-status-and-maintenance-type",["Get aggregated counts by status and by maintenance type."]],["Summaries and tenant overview","summaries-and-tenant-overview",["Read summary views for work orders, assets, locations, and tenants."]]]},{url:"/departments",sections:[["Departments",null,["Lists and gets departments for the current tenant; create, update, delete. Set tenant context before calling these methods. "]],["List departments","list-departments",["List all departments for the current tenant (from v_departments)."]],["Get by ID","get-by-id",["Fetch a single department by ID."]],["Create department","create-department",["Create a new department. Returns the new department UUID.","Required. Tenant UUID.","Required. Department display name.","Optional. Description.","Optional. Department code."]],["Update department","update-department",["Update an existing department. All fields except tenantId and departmentId are optional."]],["Delete department","delete-department",["Delete a department by tenant and department ID.","Assets","Meters"]]]},{url:"/errors",sections:[["Errors",null,["Failed SDK calls surface as SdkError: a normalized wrapper around PostgREST and Supabase errors, with message, optional code, details, and hint for debugging. "]],["SdkError","sdk-error",["All resource methods and setTenant / clearTenant normalize failures into SdkError:","Error message from PostgREST or RPC.","Optional. PostgREST/Supabase error code (e.g. PGRST301, auth codes).","Optional. Additional detail from the backend.","Optional. Hint from the backend on how to fix the issue.","You can also use normalizeError(error) to turn an unknown thrown value into an SdkError without throwing."]],["Common codes","common-codes",["Errors come from Supabase/PostgREST and your RPCs. Typical sources:","PGRST*: PostgREST (e.g. invalid filter, missing column). Check PostgREST errors for code meanings.","Auth: Supabase Auth (e.g. invalid credentials, session expired). Check Supabase Auth docs for handling.","RPC: your rpc_* functions can return custom messages and codes; details and hint may contain server-set text.","Agent / MCP contract: MCP tool errors preserve message, code, details, and hint in structured JSON, so automation can distinguish tenant-context problems, permission failures, validation errors, and retryable write conflicts."]],["Status codes","status-codes",["The SDK does not expose HTTP status codes directly; it throws on error. Under the hood, Supabase uses standard HTTP: 2xx for success, 4xx for client errors (e.g. 401 unauthorized, 403 forbidden, 404 not found), 5xx for server errors. Use SdkError.message and code / details / hint to decide how to handle failures in your app.","Permission denied (42501): When an RPC requires a permission or scope the user does not have, the backend returns an error (often with a message like “Permission denied … tenant.admin required” or “Unauthorized … workorder.edit”). See Authorization (RBAC & ABAC) for how roles, permissions, and scopes work.","Tenant context required (P0001 or MCP TENANT_CONTEXT_REQUIRED): Tenant-scoped reads and some RPCs require tenant_id in the JWT/session. In SDK code, call setTenant() and refresh the session before retrying. In MCP, use resolve_active_tenant, then set_active_tenant, and ensure the client can refresh the OAuth session (for HTTP MCP this typically means sending X-Supabase-Refresh-Token).","Retry-safe work-order creation (40001 during in-flight duplicate request): rpc_create_work_order accepts an optional client request id. If the same request is retried after the first call finishes, the original work_order_id is returned. If the first request is still in progress, the backend can respond with a retryable conflict so automation knows to retry later with the same client request id."]]]},{url:"/field-operations",sections:[["Field operations",null,["Use client.fieldOps on @workorder-systems/sdk for tool catalog (create/update + list), checkouts/returns, and shift handover workflows. Set tenant context and refresh the JWT like other tenant APIs. "]],["Tool catalog (create & update)","tool-catalog-create-and-update",["Requires tool.manage (typically admin/manager). status must be lowercase snake_case (^[a-z0-9_]+$); default is available. Only available tools can be checked out."]],["List tools and checkouts","list-tools-and-checkouts",[]],["Checkout and return","checkout-and-return",[]],["Shift handovers","shift-handovers",[]],["Permissions","permissions",["| Permission | Use |\n|------------|-----|\n| tool.manage | Create/edit tools (DB-side today) |\n| tool.checkout / tool.return | Checkout and return RPCs |\n| shift_handover.create | Create, submit, add items |\n| shift_handover.acknowledge | Acknowledge incoming handover |","Capability inventory","Labor"]]]},{url:"/floor-ops-scanning",sections:[["Floor ops and scanning",null,["Use optional barcode values on assets and parts for labels that differ from asset_number / part_number (vendor stickers, QR payloads, etc.). client.assets.resolveByScanCode and client.partsInventory.resolvePartByScanCode map a single scanned string to an entity id using a fixed resolution order enforced in the database. "]],["Overview","overview",["| Entity | Storage | Resolution order (rpc_resolve_*_by_scan_code) |\n|--------|---------|--------------------------------------------------|\n| Asset | app.assets.barcode (optional, unique per tenant) | 1) barcode 2) asset_number |\n| Part | app.parts.barcode (optional, unique per tenant) | 1) barcode 2) part_number 3) external_id |","Rows also appear on v_assets, v_parts, v_parts_with_stock, and v_mobile_assets (barcode is the last column on those views for backward-compatible column order)."]],["Asset and part barcodes","asset-and-part-barcodes",["Set barcode on create/update via the SDK (or rpc_create_asset / rpc_update_asset / rpc_create_part / rpc_update_part). To clear a barcode, pass an empty string on update (p_barcode: '')."]],["Resolve after scan","resolve-after-scan",["Trimming is applied inside the RPC. null is returned when nothing matches (your UI can show “unknown code”).","Permissions: asset.view and part.view respectively.","Equivalent RPCs: rpc_resolve_asset_by_scan_code, rpc_resolve_part_by_scan_code."]],["QR codes and deep links","qr-codes-and-deep-links",["The database does not generate QR images. Typical product patterns:","Encode a URL your SPA understands, e.g. https://app.example.com/t/{tenantSlug}/a/{assetId} or a signed token that maps server-side to an asset.","Or encode the same string you store in barcode and use resolveByScanCode after scan.","Camera UI, label printing, and Storybook demos live in your app or @workspace/ui—not in this API repo."]],["Signatures and scans as attachments","signatures-and-scans-as-attachments",["Work order (and other) attachments support a free-form kind (e.g. signature, scan). See Mobile field for registerWorkOrderAttachment and Storage paths.","Assets","Parts & inventory","Mobile field"]]]},{url:"/installation",sections:[["Installation",null,["Add @workorder-systems/sdk to get a typed client over the project’s public views and RPCs. The package ships compiled dist/ output and declarations, with no compile step in your app. "]],["Install the package","install-the-package",[]],["Peer dependency","peer-dependency",["Install @supabase/supabase-js alongside the SDK (peer range ^2.39.0). The SDK builds on the Supabase client; your app supplies both packages."]],["Create a client","create-a-client",["Pass the project URL and anon key from Project Settings → API:","Same pattern works in the browser and in Node. For edge runtimes (Cloudflare Workers, Vercel Edge, etc.), pass the platform fetch and turn off session persistence if you do not need it:","Quickstart"]],["Edge runtimes","edge-runtimes",["Use global: { fetch } so requests use the host runtime. Use auth: { persistSession: false } when there is no durable session store. For custom storage, set auth.storage (Supabase-compatible session storage)."]],["Environment variables","environment-variables",["The SDK expects SUPABASE_URL and SUPABASE_ANON_KEY in the environment you run it in. Deployed Edge Functions get all SUPABASE_* values from Supabase automatically. See Configuration.","Configuration"]]]},{url:"/integrations",sections:[["Integrations (ERP mappings)",null,["Lightweight mapping and outbound intent for ERP/HRIS-style sync: store third-party identifiers on core entities and enqueue append-only events for workers (Edge Functions, batch jobs) to process. Secrets and connector credentials do not live in Postgres. ","Use client.integrations from @workorder-systems/sdk. All writes require permission integration.manage (granted to the default admin role). Set tenant context and refresh the session before calling views or RPCs."]],["Overview","overview",["| Object | Purpose |\n|--------|---------|\n| v_integration_external_ids | Read tenant mappings (entity_type, entity_id, system_key, external_id, metadata). |\n| v_outbound_integration_events | Read recent queued events (event_type, payload, optional entity_type / entity_id). |\n| rpc_upsert_integration_external_id | Create or update one mapping. |\n| rpc_delete_integration_external_id | Remove a mapping for a given system_key. |\n| rpc_enqueue_integration_event | Append an outbound event for async delivery. |","Underlying tables live in schema int; only these public views and RPCs are meant for app clients."]],["External IDs","external-ids",[]],["Outbound events","outbound-events",["Consumers typically poll or drain the queue with service role in a trusted environment; the authenticated RPC path is for explicit enqueue from the app when a human or workflow step should record sync intent."]]]},{url:"/labor",sections:[["Labor (technicians & crews)",null,["Technicians, crews, skills, certifications, availability, shifts, work order assignments, labor actuals, and capacity views. Set tenant context before calling these methods. "]],["Overview","overview",["The client.labor resource exposes tenant-scoped views, public write RPCs for crews, technicians, and crew membership (permissions labor.crew.manage and labor.technician.manage), and scheduling RPCs:","Technicians and crews – workforce and team structure (reads + writes via RPCs)","Skills and certifications – tenant catalogs and technician linkage","Availability – recurring patterns and date overrides","Shifts and shift templates – scheduled and on-call slots","Work order assignments – which technicians are assigned to which work orders","Labor actuals – aggregated time and cost per work order","Technician capacity – scheduled minutes per technician per day","RPCs – create/update/delete crews and technicians, add/remove crew members; check shift conflicts; generate shifts from templates"]],["Technicians and crews","technicians-and-crews",["List technicians and crews for the current tenant."]],["Crews and technicians (writes)","crews-and-technicians-writes",["Requires labor.crew.manage for crews and membership, and labor.technician.manage for technician records. rpc_create_technician only accepts userId values that already have a tenant membership in that tenant."]],["Skills and certifications","skills-and-certifications",["List skill and certification catalogs and technician linkage."]],["Availability and shifts","availability-and-shifts",["List availability patterns, overrides, shifts, and shift templates."]],["Assignments and labor actuals","assignments-and-labor-actuals",["List work order assignments and aggregated labor actuals (time and cost per work order)."]],["Shift conflict detection","shift-conflict-detection",["Check for overlapping shifts for a technician before creating or updating a shift. Pass excludeShiftId when updating so the current shift is not counted as a conflict."]],["Generate shifts from templates","generate-shifts-from-templates",["Generate shift rows from shift templates for a date range. Requires tenant membership. Returns the created shifts.","Required. Tenant UUID.","Required. Start date (YYYY-MM-DD).","Required. End date (YYYY-MM-DD). Must be ≥ startDate."]]]},{url:"/locations",sections:[["Locations",null,["Lists and gets locations for the current tenant; create, update, delete. Locations support a typed hierarchy: region, site, building, floor, room, zone. Each location has a required location_type (default site), and optional code, address_line, and external_id. Parent-type rules apply: e.g. room/zone under floor, floor under building, building under site, site under region. Set tenant context before calling these methods. "]],["List locations","list-locations",["List all locations for the current tenant (from v_locations). Rows include location_type, code, address_line, external_id."]],["Get by ID","get-by-id",["Fetch a single location by ID."]],["Create location","create-location",["Create a new location. Returns the new location UUID.","Required. Tenant UUID.","Required. Location display name.","Optional. Description.","Optional. Parent location UUID.","Optional. One of: region, site, building, floor, room, zone. Default site.","Optional. Short code (unique per tenant).","Optional. Single-line address.","Optional. External system id (e.g. CAFM)."]],["Update location","update-location",["Update an existing location. All fields except tenantId and locationId are optional."]],["Bulk import","bulk-import",["Import many locations in one call. Each row must have name; optional fields: description, parent_location_id, location_type (default site), code, address_line, external_id."]],["Hierarchy and portfolio views","hierarchy-and-portfolio-views",["With tenant context set, query these views via the raw Supabase client for tree UIs, breadcrumbs, and multi-site dashboards.","v_location_hierarchy: each location with path_ids, path_names, depth (0 = root).","v_site_rollup: one row per site with aggregated counts (buildings, floors, rooms, zones, assets, work orders).","v_portfolio_overview: tenant-level summary plus one row per site (tenant metrics plus site breakdown)."]],["Map zones","map-zones",["Saved GeoJSON shapes on the locations map (optional link to a location) are managed with client.mapZones. See Map zones."]],["Delete location","delete-location",["Delete a location by tenant and location ID.","Spaces","Assets","Departments"]]]},{url:"/map-zones",sections:[["Map zones",null,["Map zones are saved shapes (polygons, lines, etc.) for the locations map, stored as GeoJSON (type + coordinates). They can optionally link to a location (for example a building footprint). "]],["Overview","overview",["Reads use v_map_zones. Writes use rpc_create_map_zone, rpc_update_map_zone, and rpc_delete_map_zone. Set tenant context before list and getById; write RPCs take an explicit tenantId."]],["List zones","list-zones",[]],["Get by ID","get-by-id",[]],["Create zone","create-zone",["geometry must be GeoJSON with type and coordinates (RFC 7946). locationId is optional; if set, it must reference a location in the same tenant.","Required. Tenant UUID.","Required. 1–255 characters.","Required. GeoJSON geometry object (type + coordinates).","Optional. Location UUID in the same tenant."]],["Update zone","update-zone",["Only tenantId and zoneId are required. Pass name, geometry, and/or locationId only for fields you want to change (omitted fields stay as they are)."]],["Delete zone","delete-zone",[]],["Access and limits","access-and-limits",["Authenticated tenant members may create, update, and delete zones for their tenant. Rate limits (rolling, per user per tenant): 30/minute for create, update, and delete.","Locations"]]]},{url:"/mcp",sections:[["MCP (Model Context Protocol)",null,["The repo ships an MCP server (apps/mcp) that exposes CMMS operations to AI assistants (Cursor, Claude Code, and other MCP hosts). It uses the same Supabase Auth session as the SDK: Bearer JWTs, RLS, and tenant-scoped RPCs — not a separate API key per tool call. ","Deep setup — Cursor + mcp-remote, Streamable HTTP, RFC 9728 metadata, production URLs — lives in the repo README linked below so it stays in sync with the code."]],["What it is","what-it-is",["Transport: Streamable HTTP at /mcp (default local base http://127.0.0.1:3765).","Authorization: Supabase is the OAuth 2.1 authorization server; the consent UI is apps/oauth in this monorepo.","Behavior: Tools validate inputs and call @workorder-systems/sdk (same surface as a typed app client)."]],["Run the server","run-the-server",["From the repository root, with SUPABASE_URL and SUPABASE_ANON_KEY in .env.local (root or apps/mcp/.env.local):",'Health check: GET /health (no auth) should return JSON with "ok": true.']],["Clients and OAuth","clients-and-o-auth",["Cursor typically runs mcp-remote against the HTTP MCP URL. The browser completes OAuth; you do not put access or refresh tokens in .cursor/mcp.json.","Production: deploy the MCP app behind HTTPS, set a public origin env var so OAuth metadata matches your URL (see README).","Read Authentication for how sessions work; MCP reuses that model."]],["Tenant context and tools","tenant-context-and-tools",["List tenants, then set active tenant so the JWT includes tenant_id where required (same idea as Tenant context). Some HTTP clients need a token refresh after switching tenant.","Generic access: sdk_catalog lists operations and JSON Schema args; sdk_invoke runs any SDK operation by id.","Shortcuts: convenience tools (e.g. work order list/get/create) wrap the same RPCs.","The recommended MCP flow is:","resolve_active_tenant","set_active_tenant","retry with the refreshed JWT if the tool response says tenant context is still missing","use summary or search tools before opening full detail"]],["Summary-first tools","summary-first-tools",["For agents, token efficiency matters. This MCP server exposes lightweight tools for selection and disambiguation before full-row reads:","work_orders_list_summary","work_orders_get_summary","assets_list_summary","parts_list_summary","pm_schedules_list_summary","Use these first when the goal is “pick the right row” rather than “inspect every field”."]],["Bundles and structured errors","bundles-and-structured-errors",["workflow_guide provides the recommended high-level order of operations.","workflow_bundle returns a curated bundle such as tenant_bootstrap, work_order_intake, work_order_lookup, or maintenance_lookup.","MCP errors preserve structured fields when available:","message","code","details","hint","For example, missing tenant context returns an explicit guidance payload instead of silently returning an empty list where possible.","Under the hood, these flows now align more closely with shared SDK ergonomics:","client.workOrders.listSummary(...)","client.assets.listSummary(...)","client.partsInventory.listSummary(...)","client.pm.listSchedulesSummary(...)","client.agent.resolveTenant()","client.agent.ensureTenant(...)","client.agent.createWorkOrderSafe(...)","For a full agent-builder guide, see Building agents."]],["Full reference","full-reference",["apps/mcp/README.md — Cursor config, mcp-remote callback ports, Claude Code HTTP transport, env vars, and troubleshooting.","Quickstart","Tenant context","Building agents"]]]},{url:"/meters",sections:[["Meters",null,["Lists asset meters and meter readings for the current tenant; create, update, record readings, delete meters. Set tenant context before calling these methods. "]],["List meters","list-meters",["List all asset meters for the current tenant (from v_asset_meters)."]],["Get readings","get-readings",["List meter readings (from v_meter_readings)."]],["Create meter","create-meter",["Create a new meter for an asset. Returns the new meter UUID.","Required. Tenant UUID.","Required. Asset UUID.","Required. Meter type key (e.g. usage, counter).","Required. Meter name.","Required. Unit (e.g. hours, miles, kWh).","Optional. Default 0. Initial reading value.","Optional. Default increasing. Direction for rollover.","Optional. Default 0. Decimal places for display.","Optional. Description."]],["Update meter","update-meter",["Update an existing meter. All fields except tenantId and meterId are optional."]],["Record reading","record-reading",["Record a meter reading. Returns the reading record UUID.","Required. Tenant UUID.","Required. Meter UUID.","Required. Reading value.","Optional. ISO date string.","Optional. Default manual. Reading type key.","Optional. Notes."]],["Automated readings (API keys)","automated-readings-api-keys",["For unauthenticated devices or jobs, use a tenant API key and the ingest-meter-reading Edge Function. That path records readings as automated (not the interactive client.meters.recordReading flow). See Tenant API keys."]],["Delete meter","delete-meter",["Delete a meter by tenant and meter ID.","Assets","Work orders"]]]},{url:"/mobile-field",sections:[["Mobile field",null,["Offline sync, start/stop job, add note, register attachment, and lightweight mobile views with optional GPS. Set tenant context before use. "]],["Overview","overview",["The database and SDK support mobile-first field workflows for technicians:","| Capability | SDK / API |\n|------------|-----------|\n| Offline sync | client.mobile.sync(params). Single JSON payload of work orders, assets, locations, time entries, attachments, check-ins, notes. Use updatedAfter for incremental sync; optional technicianId to filter work orders. |\n| Start job | client.mobile.startWorkOrder(params). Transition to in_progress and create a check-in; optional GPS. Returns check-in id. |\n| Stop job | client.mobile.stopWorkOrder(params). Optionally log time, add note, complete work order with cause/resolution, and set completed-at GPS. |\n| Add note | client.mobile.addNote(params). Add a note to a work order; optional GPS. Returns note id. |\n| Register attachment | client.mobile.registerWorkOrderAttachment(params). Register an existing file (e.g. after resumable upload) as a work order attachment. Returns attachment id. |\n| Mobile views | client.mobile.listMobileWorkOrders(), listMobileAssets(), listMobileLocations(), etc. Minimal columns for offline use. |","Attachments (photos, documents, signatures, scans) are supported for work orders, assets, and locations. Work order attachments can be created by uploading to Storage (trigger creates the link) or by registering an existing file with registerWorkOrderAttachment. Asset and location attachments use Storage paths tenant_id/asset/asset_id/filename and tenant_id/location/location_id/filename."]],["Offline sync","offline-sync",["Fetch a single JSON payload for mobile offline sync. Returns work_orders, assets, locations, time_entries, attachments, check_ins, and notes. Use updatedAfter (ISO timestamp) for incremental sync; pass technicianId to restrict work orders to those assigned to that technician.","Required. Tenant UUID.\nOptional. ISO timestamp; only rows updated/created after this are returned. Omit for full sync.\nOptional. Max rows per entity type (default 500, max 2000).\nOptional. When set, work_orders are filtered to those assigned to this technician (assigned_to or work_order_assignments)."]],["Start work order","start-work-order",["Transition the work order to in_progress and create a check-in record. Optional GPS (latitude, longitude, accuracy_metres). Returns the check-in id. Requires the current user to be assigned to the work order or have workorder.edit."]],["Stop work order","stop-work-order",["Optionally log time (with optional GPS), add a note, and/or complete the work order with cause and resolution. When completing, optional completed_at_latitude and completed_at_longitude are set on the work order. Requires assigned or workorder.edit.","Optional. Default true. If true, transitions work order to completed.\nOptional. If set, logs a time entry with optional GPS.\nOptional. Adds a work order note (with optional GPS).\nOptional. GPS for time entry and/or note and completed-at.\nOptional. Set when completing the work order."]],["Add note","add-note",["Add a note to a work order. Optional GPS when the note was taken. Returns note id. Permission: assigned or workorder.edit."]],["Register attachment","register-attachment",["When the client uploads a file to Storage first (e.g. resumable upload) and then needs to link it to a work order, use registerWorkOrderAttachment. The file must already exist in app.files (e.g. created by a custom flow or by uploading to a path that does not use the work-order trigger). Validates that the file and work order belong to the tenant. Returns attachment id.","For the standard flow (upload to Storage path tenant_id/work_order/{work_order_id}/filename), the trigger creates the file and attachment automatically; use client.workOrders.listAttachments(workOrderId) to get the new row. Use registerWorkOrderAttachment only when you have an existing file id (e.g. after a resumable upload that wrote to Storage and created app.files separately)."]],["Mobile views","mobile-views",["Lightweight views with minimal columns for mobile clients. Set tenant context, then query via the SDK list methods or directly from Supabase.","Other list methods: listMobileAssets(), listMobileLocations(), listMobileTimeEntries(), listMobileAttachments(), listMobileCheckIns(), listMobileNotes(). Use updated_at (or created_at for check_ins and notes) for incremental sync when not using client.mobile.sync()."]],["Attachments for assets and locations","attachments-for-assets-and-locations",["Attachments (photos, documents, signatures, scans) are supported for assets and locations as well as work orders.","| Entity | Storage path convention (storage.foldername = 3 segments) | View |\n|--------|--------------------------------------------------------------|------|\n| Work order | tenant_id/work_order/work_order_id/filename | v_work_order_attachments |\n| Asset | tenant_id/asset/asset_id/filename | v_asset_attachments |\n| Location | tenant_id/location/location_id/filename | v_location_attachments |\n| Other | tenant_id/<entity_type>/<entity_id>/filename (e.g. part, purchase_order, incident) | v_entity_attachments |","Upload to the attachments bucket with the appropriate path; a trigger creates app.files and app.entity_attachments. Use client.supabase.storage.from('attachments').createSignedUrl(...) with bucket_id and storage_path from the view rows. Kind values (e.g. photo, document, signature, scan) are free-form; document in your UI for consistency.","Raw queries:"]],["GPS and check-ins","gps-and-check-ins",["Optional GPS is stored on:","Check-ins (app.work_order_check_ins): latitude, longitude, accuracy_metres when the technician checked in.","Time entries (app.work_order_time_entries): latitude, longitude, accuracy_metres when the entry was logged. Use client.workOrders.logTime({ ...params, latitude, longitude, accuracyMetres }).","Work orders: completed_at_latitude, completed_at_longitude when the work order was completed (set by client.mobile.stopWorkOrder when completing with GPS).","All GPS columns are nullable. Use numeric for lat/long in the database; the SDK accepts number for params.","Work orders","Tenant context","Assets"]]]},{url:"/notifications",sections:[["Notifications",null,["Per-user, per-tenant in-app notifications (title, body, optional entity link, payload). Use client.notifications on @workorder-systems/sdk, or call client.supabase directly—views and RPCs are typed on the SDK Database type. Set tenant context and refresh the session before tenant-scoped calls, same as other APIs. ","client.notifications.list() reads v_my_notifications (PostgREST filters, optional unreadOnly). listForTenant(tenantId) uses rpc_list_my_notifications when you prefer an explicit tenant id argument."]],["List notifications","list-notifications",[]],["Mark as read","mark-as-read",["Pass one or more notification ids returned from the list above."]],["Preferences","preferences",["Toggle in-app delivery for a given event_key (string defined by the backend for each notification type). Requires notification.preference.manage (included on default roles such as member and admin)."]],["Advanced: raw PostgREST","advanced-raw-postg-rest",["Use client.supabase when you need custom filters or to avoid the resource wrapper."]],["Background processing","background-processing",["rpc_process_due_notifications is intended for trusted server contexts (for example Supabase pg_cron or an Edge Function using the service role). It is not exposed on client.notifications and must not be called from end-user clients. Your deployment wires when and how due notifications are materialized."]]]},{url:"/parts-inventory",sections:[["Parts & inventory",null,["Parts catalog, suppliers, stock locations and bins, on-hand quantities, re-order rules, part reservations and usage linked to work orders, and basic purchasing (requisitions, purchase orders, receipts). Set tenant context before calling these methods. "]],["Overview","overview",["The client.partsInventory resource provides:","Parts catalog – list parts with or without aggregated stock (on-hand, reserved, available)","Suppliers – list and get by id; create/update via RPCs","Inventory locations – hierarchy (warehouse, aisle, shelf, bin); stock levels per part per bin","Reservations – parts reserved for work orders; list by work order","Part usage – parts issued/consumed on work orders; list by work order","Purchasing – open requisitions, open POs, PO receipt status; draft requisition + line CRUD via RPCs; receive PO and create PO via RPCs","RPCs – reserve parts, issue parts to work order, receive PO, create PO, create/update part, create/update supplier, requisition create/lines/delete (draft-only)","Supplier contracts – create/update contracts and rate lines (supplier.edit); read v_supplier_contracts, v_supplier_contract_rates; vendor roll-ups v_vendor_spend_by_supplier, v_work_order_counts_by_primary_supplier","All data is tenant-scoped. Permissions (e.g. part.create, inventory.usage.record, purchase_requisition.create, purchase_requisition.edit, purchase_order.receive) are enforced by the RPCs."]],["Parts and stock","parts-and-stock",["Parts with aggregated stock (total on-hand, total reserved, available = on-hand − reserved). Use for dashboards and re-order logic.","Stock by part and inventory location (bin). Use for put-away and pick lists.","Catalog-only list (no aggregates)."]],["Suppliers and inventory locations","suppliers-and-inventory-locations",[]],["Supplier contracts and vendor metrics","supplier-contracts-and-vendor-metrics",["Commercial agreements and optional rate lines are stored per supplier. Reporting views aggregate work order vendor cost lines and primary supplier assignment counts.","Requires supplier.edit for createSupplierContract, updateSupplierContract, addSupplierContractRate."]],["Reservations and usage","reservations-and-usage",["Parts reserved for work orders (status: reserved, issued, released, cancelled). Parts consumed on work orders."]],["Purchasing","purchasing",["Open requisitions (draft, submitted, approved). Open POs (draft, sent, partially_received). PO receipt status (quantity ordered, received, balance per line)."]],["Requisition RPCs (draft)","requisition-rpcs-draft",["Create a draft requisition, add or update lines, remove lines, or delete the whole requisition. Line changes and delete are allowed only while status is draft. Submitting or approving requisitions for workflow is not covered here (no public submit RPC in this wave).","purchase_requisition.create – createPurchaseRequisition","purchase_requisition.edit – addPurchaseRequisitionLine, updatePurchaseRequisitionLine, removePurchaseRequisitionLine, deletePurchaseRequisition"]],["RPCs (create/update)","rpcs-create-update",["All RPCs require tenant context and the appropriate permission. Pass tenantId in params for consistency.","Reserve parts – creates a reservation for a work order. Requires inventory.reservation.create.","Issue parts to work order – decrements stock, creates inventory transaction and part_usage record; optionally marks a matching reservation as issued. Requires inventory.usage.record.","Receive purchase order – creates a receipt and receipt lines, updates PO line quantity_received, and updates stock_levels when to_inventory_location_id is set. Requires purchase_order.receive.","Create purchase order – creates a PO and optional lines. Requires purchase_order.create. Use externalId for ERP sync.","Create part – requires part.create. Use externalId for ERP sync.","Update part – requires part.edit. Only provided fields are updated.","Create supplier – requires supplier.create. Use externalId for ERP sync.","Update supplier – requires supplier.edit.","Work orders","Costs & lifecycle"]]]},{url:"/plugins",sections:[["Plugins",null,["Lists the catalog of available plugins (v_plugins) and tenant plugin installations (v_plugin_installations). Install, update, and uninstall plugins for a tenant. Outbound webhooks are driven by audit.entity_changes when you add allowlisted subscriptions; deliveries are processed in-database via pg_net and pg_cron (see How to build a plugin and Building plugins). Installing and managing installations and subscriptions requires tenant.admin permission. Set tenant context before listing or managing installations. "]],["List plugins (catalog)","list-plugins-catalog",["List all available plugins (from v_plugins). No tenant context required."]],["Get plugin by ID","get-plugin-by-id",["Fetch a single plugin from the catalog by ID."]],["List installations","list-installations",["List plugin installations for the current tenant (from v_plugin_installations). Requires tenant context and tenant.admin permission."]],["Install plugin","install-plugin",["Install a plugin for a tenant. Returns the installation UUID. Requires tenant.admin permission. Rate limited (e.g. 10 requests per minute per user).","Required. Tenant UUID.","Required. Plugin key (from catalog).","Optional. Opaque reference to stored secret (e.g. API key); not the secret value.","Optional. Installation config (JSON object)."]],["Update installation","update-installation",["Update a plugin installation (status, secret_ref, config). Requires tenant.admin permission.","Required. Tenant UUID.","Required. Installation UUID (from listInstallations).","Optional. Status (e.g. active, paused).","Optional. Opaque reference to stored secret.","Optional. Installation config (JSON object)."]],["Uninstall plugin","uninstall-plugin",["Uninstall a plugin for a tenant. Requires tenant.admin permission. Rate limited.","Required. Tenant UUID.","Required. Installation UUID."]],["Webhook subscriptions","webhook-subscriptions",["Allowlist which audited tables and operations should enqueue outbound webhook deliveries for an installation. No subscription rows means no outbound events for that installation. Requires tenant.admin and tenant context.","Installation config should include a webhook_url string for the subscriber HTTPS endpoint. Optional: timeout_ms (1000–120000), and headers (json object of non-secret header names/values). Signing uses Supabase Vault: store the HMAC secret under a unique name, and set secret_ref on the installation to that same name (see Building plugins)."]],["Recent webhook deliveries","recent-webhook-deliveries",["Tenant admins can read metadata for recent outbound deliveries (status, attempts, last error). Payload bodies are not exposed here.","Processing is normally scheduled every minute (pg_cron calling rpc_process_plugin_deliveries). For automation or diagnostics, a client using the service role JWT can call client.plugins.processDeliveries(batchSize?) (not available to end-user sessions).","Tenant context","Authorization","Work orders"]]]},{url:"/plugins-building",sections:[["Building plugins",null,["Build an optional extension or integration on top of the Work Order Systems API. Plugins are separate services or UIs that call the public API; they do not change the database schema. ","New to plugins? Start with the step-by-step guide: How to build a plugin."]],["What is a plugin?","what-is-a-plugin",["Module: First-party core capability that owns schema and migrations.","Plugin: Optional behavior or UI on top of existing modules. Uses the public API (views for reads, RPCs for writes). No schema changes.","Integration: A plugin that connects to external systems (e.g. ticketing, messaging, CMMS, BI tools).","Your plugin runs as its own app or service (serverless function, worker, backend). Use server-side Supabase credentials for catalog and admin operations, and end-user sessions for tenant-scoped actions (e.g. from your frontend or admin app). All reads and writes go through the public API (views + RPCs)."]],["Plugin lifecycle","plugin-lifecycle",["Define your plugin: key, name, description, and whether it's an integration.","Register it in the catalog: call rpc_register_plugin from a trusted backend (never from the browser or with the anon key).","Expose UI: let tenant admins install and configure the plugin (e.g. with client.plugins from their browser or your admin app).","Run plugin logic: in your service, use the public views and RPCs to read and write data."]],["Register plugin in the catalog","register-plugin-in-the-catalog",["Registration is backend-only. Use a Supabase client with server-side credentials. Don't use the @workorder-systems/sdk client or the anon key from the browser.","Registration must happen from a secure backend. Don't use the browser SDK or anon key."]],["Install plugin for a tenant","install-plugin-for-a-tenant",["Tenant admins install plugins from your frontend or admin app. Use the public SDK:","List and update installations with client.plugins.listInstallations() and client.plugins.updateInstallation(params). See Plugins."]],["Outbound webhooks (audit-driven)","outbound-webhooks-audit-driven",["The database enqueues outbound deliveries when rows appear in audit.entity_changes, but only for installations that have explicit subscription allowlists (int.plugin_webhook_subscriptions via rpc_upsert_plugin_webhook_subscription). This keeps noise low: without subscriptions, nothing is sent.","Vault: Create a secret in Supabase Vault with a stable name (for example my_plugin_hmac_prod). The plaintext is your shared signing secret.","Install: Set secretRef on the installation to that same name (not the secret value). Set config.webhook_url to your HTTPS endpoint. Optional: config.timeout_ms, config.headers (non-secret only).","Subscribe: Upsert a subscription for each (table_schema, table_name) and operations (INSERT / UPDATE / DELETE). For UPDATE, you can pass changed_fields_allowlist so only relevant column changes fire events.","Payload: Subscribers receive JSON with v, tenant_id, installation_id, plugin_key, audit (id, schema, table, record_id, operation, changed_fields), and snapshot (either metadata-only or full old_data/new_data when include_payload is true). HMAC-SHA256 (hex) of payload::text (UTF-8) is sent as header X-Plugin-Signature when a Vault secret resolves.","Delivery: pg_net posts asynchronously; rpc_process_plugin_deliveries (scheduled by pg_cron every minute) collects responses, retries with exponential backoff, and marks dead after repeated failures. Treat delivery as at-least-once; dedupe using audit.id and X-Plugin-Delivery-Id."]],["Inbound webhooks (HMAC)","inbound-webhooks-hmac",["Partners can call rpc_plugin_ingest_webhook with the anon or authenticated role (no end-user session required). Arguments: p_plugin_key, p_installation_id, p_payload (jsonb), p_signature (hex). The signature must match HMAC-SHA256 over p_payload::text using the same Vault secret referenced by secret_ref. Rate limiting is applied using the installation’s installed_by user when present.","Allowlisted actions today include noop and work_order.create (with data.title and optional catalog-valid fields). Extend with care—never execute arbitrary SQL from webhook bodies."]],["Use the public API from your plugin","use-the-public-api-from-your-plugin",["Treat the Work Order Systems API as your backend:","Reads: Query public views like v_work_orders, v_assets, v_work_order_attachments, v_pm_*, v_dashboard_*, and so on.","Writes: Call public RPCs like rpc_create_work_order, rpc_log_work_order_time, rpc_install_plugin, rpc_update_plugin_installation, rpc_upsert_plugin_webhook_subscription, rpc_plugin_ingest_webhook, rpc_create_pm_schedule, and others.","Use @supabase/supabase-js in your backend with server-side credentials for tenant-admin or system operations. Use end-user JWTs when acting on behalf of a specific user.","Public contract: Views use the v_* prefix for reads; RPCs use the rpc_* prefix for writes and actions. For full reference, see the resource pages in this docs site (Work orders, Assets, PM, Dashboard, Plugins, Authorization, etc.)."]],["Next steps","next-steps",["How to build a plugin: ordered checklist from catalog to first delivery.","Local webhook receiver sample app: plugins/example (pnpm --filter work-order-systems-example dev). See its README for host.docker.internal and HMAC env vars.","Plugins: list and manage plugins","Work orders: work order API reference","Authentication: sign in with Supabase Auth"]]]},{url:"/pm",sections:[["Preventive maintenance (PM)",null,["Manage PM templates and schedules for assets; generate work orders when PMs are due. Set tenant context before calling these methods. "]],["List templates and schedules","list-templates-and-schedules",[]],["Create and update template","create-and-update-template",["Create a PM template that defines trigger configuration and default work order fields. Requires tenant.admin. Returns the template UUID.","Update an existing template:"]],["Create and update schedule","create-and-update-schedule",["Create a PM schedule for an asset. Returns the schedule UUID.","Update an existing schedule:"]],["Delete schedule","delete-schedule",["Delete a PM schedule."]],["Dependencies and automatic generation","dependencies-and-automatic-generation",["Create dependencies between PM schedules, generate due PMs on demand from your app, or rely on the database scheduler.","Automatic (hosted Supabase / pg_cron): pg_cron runs public.rpc_process_due_pm_generation() about every 15 minutes (postgres role only; not exposed on the PostgREST API). It scans all tenants for active schedules with auto_generate and a due next_due_date, then creates work orders the same way as generateDuePms. It skips a schedule when a work order already exists in a non-final status (per cfg.status_catalogs.is_final), which prevents duplicate WOs for calendar-style schedules until next_due_date is advanced. Usage-based PMs are still created when meter readings cross thresholds (rpc_record_meter_reading), not by this job. Manual PMs still use triggerManualPm.","Trigger a manual PM for a schedule:"]],["Due, overdue, upcoming, history","due-overdue-upcoming-history",["List PM instances across different states."]]]},{url:"/projects",sections:[["Projects",null,["Projects group work for reporting and cost roll-up. The SDK exposes v_projects for reads and client.projects.create, update, and delete (via public RPCs; permission project.manage, usually on admin). "]],["Overview","overview",["Set tenant context before calling these methods. Rows include id, tenant_id, name, optional code (unique per tenant when set), description, created_at, and updated_at."]],["List projects","list-projects",[]],["Get by ID","get-by-id",[]],["Create project","create-project",["Creates a project and returns the new UUID. Requires project.manage. name is required; code and description are optional."]],["Update project","update-project",["Partial updates: pass null for fields you do not want to change (per RPC contract). Requires project.manage."]],["Delete project","delete-project",["Removes the project row. Work orders that referenced it keep project_id cleared (FK behavior), not deleted. Requires project.manage."]],["Work orders and cost roll-up","work-orders-and-cost-roll-up",["Pass projectId when creating a work order so labor, parts, and vendor costs roll up under that project. Use client.costs.costRollup() with groupBy: 'project' for aggregates.","Costs & lifecycle","Work orders"]]]},{url:"/quickstart",sections:[["Quickstart",null,["Install the client, wire in your Supabase URL and anon key, then call a resource. Most flows need Auth and tenant context for tenant-scoped data. This page shows the minimal path. ","Grab the URL and anon key under Project Settings → API. Tenant-scoped lists require a signed-in user and client.setTenant(...) plus a session refresh. See Tenant context."]],["Install the SDK","install-the-sdk",["The SDK exposes resources (tenants, workOrders, assets, …) and helpers for tenant context on top of a typed client.supabase.","Installation details"]],["How the pieces connect","how-the-pieces-connect",["Your code talks to PostgREST (views + RPCs). Postgres and RLS enforce tenant safety under the hood.","Mermaid is enabled site-wide: use a fenced code block with the mermaid language tag, or the exported Mermaid component with a chart string prop."]],["Create a client and call the API","create-a-client-and-call-the-api",["Listing tenants (after sign-in) does not require tenant context. Work orders and most domain APIs do: set tenant and refresh the session first.","Reuse the same clientRequestId if your automation retries the same create request. The API returns the original workOrderId instead of creating a duplicate row.","Tenant-scoped calls need both a signed-in user and a JWT that includes tenant_id after setTenant and session refresh:","Tenant context","Work orders"]],["Next steps","next-steps",["Installation: peers, edge runtimes, env vars","Authentication: Supabase Auth and the SDK session","Tenant context: when and how to set tenant_id","Errors: SdkError and common codes"]]]},{url:"/request-portal-and-sla",sections:[["Request portal and SLA",null,["These features are what make the platform feel like a real CMMS to requestors and coordinators: self-service requests, promised response/resolution times, and clear breach signals. The database stores requested_by, computes due times from per-tenant SLA rules, and exposes read models for UI and reporting. ","Use @workorder-systems/sdk with tenant context and a refreshed session (JWT with tenant_id) like other tenant-scoped APIs."]],["Permissions and roles","permissions-and-roles",["Key permissions (see migration cmms_core_suppliers_portal_sla):","| Permission | Purpose |\n|------------|---------|\n| workorder.request.create | Submit a portal request |\n| workorder.request.view.own | See v_my_work_order_requests |\n| workorder.request.view.any | See all requests (coordinator) |\n| workorder.acknowledge | Set acknowledged_at for response SLA |\n| tenant.sla.manage | Create/update SLA rules |","The default requestor role is suited to portal users; admin / manager typically include SLA management and acknowledgment."]],["Submit a request (portal)","submit-a-request-portal",["Inserts a maintenance_requests row (status submitted), then converts it to a work order in the same RPC. The returned UUID is still the work order id (backward compatible). requested_by is the signed-in user. Location and asset are validated against ABAC scopes (user_can_request_work_order_at_locations). Rate limited."]],["List my requests","list-my-requests",["Read-only view of work orders you submitted (v_my_work_order_requests).","Staff still use client.workOrders.list() from v_work_orders (RLS varies by role; requestors only see their own rows in the full list)."]],["Maintenance requests (pre-WO)","maintenance-requests-pre-wo",["For a two-step flow (request row first, work order when staff is ready), use rpc_create_maintenance_request. Use draft to capture intent without portal ABAC on locations (tenant/asset checks still apply); only submitted rows can be converted. Staff run rpc_convert_maintenance_request_to_work_order (workorder.edit). The usual portal button keeps using createRequest, which submits and converts in one step."]],["Communication log","communication-log",["Append read-only communication events on a work order (v_work_order_comms) for coordinator and portal audit trails. Requester, assignee, or workorder.edit may append via rpc_add_work_order_comms_event."]],["SLA rules (admin)","sla-rules-admin",["Define response and resolution intervals per priority, with an optional maintenance type override. Intervals are Postgres interval text (e.g. 30 minutes, 4 hours, 3 days). Generic rule: maintenanceTypeKey omitted. More specific rule: set maintenanceTypeKey to match the work order’s maintenance type.","New and updated work orders get sla_response_due_at and sla_resolution_due_at recomputed from active rules (maintenance-specific rule wins, else generic for that priority)."]],["SLA on work orders","sla-on-work-orders",["v_work_orders includes portal and SLA columns, for example:","requested_by, acknowledged_at","sla_response_due_at, sla_resolution_due_at","sla_response_breached_at, sla_resolution_breached_at","Use client.workOrders.getById(id) or list() as usual; types come from WorkOrderRow."]],["Acknowledge (first response)","acknowledge-first-response",["Sets acknowledged_at once (idempotent), satisfying response SLA tracking from the coordinator side."]],["SLA status for dashboards","sla-status-for-dashboards",["v_work_order_sla_status exposes derived response_sla_breached and resolution_sla_breached flags for all work orders in the tenant (for dispatch boards and alerts)."]],["Coordinator SLA queue","coordinator-sla-queue",["v_work_orders_sla_open lists non-final work orders that have SLA due times—useful for dispatch triage (minutes remaining, breach flags).","Work orders","Notifications"]]]},{url:"/safety-compliance",sections:[["Safety & compliance",null,["Inspection templates, checklists, schedules, and runs tied to assets, locations, and work orders; incidents and near-misses with corrective actions; compliance reporting for regulated environments (F&B, pharma, healthcare). Set tenant context before calling these methods. "]],["List inspections and incidents","list-inspections-and-incidents",[]],["Inspection templates and schedules","inspection-templates-and-schedules",["Create and update inspection templates (e.g. daily safety round, GMP checklist). Template create/update requires tenant.admin. Checklist items are passed as an array.","Create and update inspection schedules. At least one of assetId or locationId is required."]],["Inspection runs and completion","inspection-runs-and-completion",["Create an inspection run (scheduled or ad hoc). At least one of assetId or locationId is required. Optionally link to a work order or schedule.","Complete a run and optionally submit item results (pass/fail/na/not_checked)."]],["Incidents and corrective actions","incidents-and-corrective-actions",["Create and update incidents (type: incident, near_miss, or event; severity: low, medium, high, critical).","Add and manage corrective/preventive/containment actions."]],["Compliance reporting","compliance-reporting",["Read-only RPCs for audit and compliance reports: inspection history with pass/fail counts, and incident report with action counts.","All changes to inspection and incident data are written to the audit log (audit.entity_changes) for audit-ready histories in regulated environments."]]]},{url:"/scheduling",sections:[["Scheduling & dispatch",null,["Schedule work orders onto calendars or boards by technician, crew, asset, or location. Use the client.scheduling resource to list blocks, schedule or reassign work (drag-and-drop style), validate slots, and unschedule. Set tenant context before calling these methods. "]],["Overview","overview",["The client.scheduling resource provides:","Views – List schedule blocks for the current tenant, optionally filtered by technician, crew, asset, or location. Use for calendar/board UIs; filter by date range in the client.","Schedule – Create or replace a schedule block for a work order (assign to a technician or crew, set start/end time).","Update – Change a block’s time, technician/crew, or location/asset (reassign or move on the board).","Validate – Check a candidate slot for shift conflicts, other schedule blocks, weekly availability patterns and date overrides, SLA (due_date plus sla_response_due_at / sla_resolution_due_at when set), asset required skills vs the technician’s skills (when the work order has an asset with asset_required_skills), and crew validation (aggregates checks for up to 50 active members). Pattern times use each row’s timezone, or UTC when null.","Unschedule – Remove the schedule block for a work order (by block id or work order id). Assignments are left as-is; only the slot is removed.","One block per work order is assumed: scheduling again for the same work order replaces the existing block."]],["List by technician, crew, asset, location","list-by-technician-crew-asset-location",["List schedule blocks from the appropriate view. Apply date-range filtering in the client (e.g. filter rows where start_at/end_at fall in the visible range).","Each row includes work_order_title, work_order_status, work_order_priority, work_order_due_date, and effective_location_id / effective_asset_id for display."]],["Schedule work order","schedule-work-order",["Create a schedule block for a work order. Exactly one of technicianId or crewId must be set. Replaces any existing block for that work order.","Required. Work order UUID.\nOptional. Technician UUID. Exactly one of technicianId or crewId required.\nOptional. Crew UUID. Exactly one of technicianId or crewId required.\nRequired. Block start (ISO timestamptz).\nRequired. Block end (ISO timestamptz). Must be after startAt.\nOptional. Override location for board grouping.\nOptional. Override asset for board grouping."]],["Update schedule block","update-schedule-block",["Update a block’s time, technician/crew, or location/asset. Use for drag-and-drop reassignment or rescheduling.","Required. Schedule block UUID.\nOptional. New technician. Cannot set both technicianId and crewId.\nOptional. New crew. Cannot set both technicianId and crewId.\nOptional. New block start.\nOptional. New block end.\nOptional. New location for board.\nOptional. New asset for board."]],["Validate schedule","validate-schedule",["Check a candidate slot before scheduling. Pass technician or crew (crew runs the same checks for each active member, up to 50). Optionally pass work order id for SLA fields, priority, and skill gaps (work order’s asset must have rows in asset_required_skills; technicians need matching technician_skills). Returns multiple rows when several checks apply.","Optional. Technician UUID.\nOptional. Crew UUID. Validates each active member; issue rows use check_type suffix _member.\nOptional. Candidate slot start.\nOptional. Candidate slot end.\nOptional. Work order for SLA (due_date, sla_*_due_at), priority, and asset skill gaps.\nOptional. When updating a block, pass its id to avoid self-conflict.","Severity values: error, warning, info, breach. Check types include: conflict, availability, skill, sla, priority, input, crew, and *_member (crew aggregation)."]],["Unschedule work order","unschedule-work-order",["Remove the schedule block for a work order. You can pass the schedule block id or the work order id. Work order assignments are not removed; only the scheduled slot is deleted.","Optional. Schedule block UUID to delete.\nOptional. Work order UUID; deletes the block for that work order. One of scheduleBlockId or workOrderId must be set."]]]},{url:"/spaces",sections:[["Spaces",null,["Spaces attach room/zone-level attributes to a location: usage type, capacity, status, area_sqft, and optional attributes (e.g. amenities, BMS zone id). One space per location (typically a location with location_type room or zone). Work orders continue to reference location_id; join to spaces when you need usage or status. Set tenant context before calling these methods. "]],["List spaces","list-spaces",["List all spaces for the current tenant (from v_spaces). Rows include location_name, location_type."]],["Get by ID","get-by-id",["Fetch a single space by ID."]],["Get by location","get-by-location",["Fetch the space for a given location (at most one space per location)."]],["Create space","create-space",["Create a space for a location. Returns the new space UUID.","Required. Tenant UUID.","Required. Location UUID (typically a room or zone). Must belong to the tenant.","Optional. E.g. office, conference, patient_room, lab, storage, lobby.","Optional. Occupancy/person capacity.","Optional. available, occupied, maintenance, reserved, offline. Default available.","Optional. Area in square feet.","Optional. JSON object for extensible data."]],["Update space","update-space",["Update an existing space. All fields except tenantId and spaceId are optional."]],["Delete space","delete-space",["Delete a space by tenant and space ID.","Locations","Work orders"]]]},{url:"/tenant-api-keys",sections:[["Tenant API keys",null,["Tenant API keys are long-lived secrets scoped to one tenant. They are intended for devices, scripts, or backends that cannot use a user session — for example, posting automated meter readings through the ingest-meter-reading Edge Function. "]],["What they are (and are not)","what-they-are-and-are-not",["They are not a replacement for the Supabase anon key or JWT: PostgREST and the SDK’s normal calls still expect Supabase Auth (or the service role on the server). A tenant API key does not let you call arbitrary RPCs as that tenant from the public API.","They are opaque strings stored only as a SHA-256 hash in the database. When you create a key, the raw value is returned once (wosk_… prefix); you cannot retrieve it later — only metadata (name, prefix, timestamps).","Managing keys requires the tenant.admin permission (same pattern as other tenant-scoped admin RPCs)."]],["SDK: create, list, revoke","sdk-create-list-revoke",["Use a signed-in Supabase client (user with tenant admin). Pass the tenant UUID explicitly on each call."]],["Rate limits","rate-limits",["Server-side rate limits apply per user per tenant (rolling windows):","Create: 10 per minute","List: 30 per minute","Revoke: 20 per minute"]],["Meter ingest Edge Function","meter-ingest-edge-function",["The repo includes functions/ingest-meter-reading. When deployed, it validates the tenant API key with the service role, then records a reading with reading_type = 'automated' via rpc_record_meter_reading_automated.","Endpoint (hosted Supabase): https://<project-ref>.supabase.co/functions/v1/ingest-meter-reading","Headers (either form):","Authorization: Bearer <tenant_api_key>","or X-API-Key: <tenant_api_key>","Body (JSON):",'Responses: 201 with { "readingId": "uuid" } on success; 401 for missing/invalid/expired keys; 4xx for validation or tenant/meter mismatches. The function needs SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY in its environment (set automatically when deployed in Supabase).',"Local testing: see apps/supabase/README.md and the root script that serves functions (e.g. supabase:functions).","Meters","Authentication","Configuration"]]]},{url:"/tenant-context",sections:[["Tenant context",null,["The API is multi-tenant. Work orders, assets, locations, and similar resources are scoped to a current tenant you choose for the session. "]],["Why tenant context?","why-tenant-context",["Scoped views and RPCs read tenant_id from the JWT. Call client.setTenant(tenantId) (which invokes rpc_set_tenant_context), then refresh the session so the new claim is issued. Without that, many queries return empty results or RPCs may error."]],["Set tenant context","set-tenant-context",["Call setTenant(tenantId) with a tenant the user is a member of. Then refresh the session so the JWT includes the new context (e.g. fetch the session and set it again).","Without that refresh, the JWT may still omit tenant_id, so tenant-scoped calls can fail or return nothing.","HTTP MCP clients: after calling set_active_tenant, send\nX-Supabase-Refresh-Token with the Supabase refresh_token\nso the MCP server can refresh the access token in-request. If you do not provide\na refresh token, reconnect OAuth or otherwise obtain a fresh Bearer token before\nretrying tenant-scoped tools."]],["Clear tenant context","clear-tenant-context",["When switching tenants or logging out, clear the context first:","Then set the new tenant and refresh, or sign out with client.supabase.auth.signOut()."]],["Which resources are tenant-scoped?","which-resources-are-tenant-scoped",["Not tenant-scoped: client.tenants.list() and client.tenants.getById(id). They return tenants the user is a member of; no tenant context needed.","Tenant-scoped: work orders, assets, locations, departments, meters, plugins, authorization, catalogs, PM, dashboard, audit. Always call setTenant(tenantId) and refresh the session before using these.","Tenants API","Work orders API"]]]},{url:"/tenants",sections:[["Tenants",null,["Lists tenants the current user is a member of; create tenants, invite users, assign roles. Tenant context is not required for tenants; use setTenant for work orders, assets, and other tenant-scoped resources. "]],["List tenants","list-tenants",["List all tenants the authenticated user is a member of (from v_tenants)."]],["Get by ID","get-by-id",["Fetch a single tenant by ID."]],["Create tenant","create-tenant",["Create a new tenant. The authenticated user becomes a member and is assigned the admin role. Returns the new tenant UUID.","Required. Tenant display name.","Required. Unique slug."]],["Invite user","invite-user",["Invite a user to a tenant with a role (e.g. admin, member). The invitee receives an invite; they must accept to join.","Required. Tenant UUID.","Required. Invitee email.","Required. Role key (e.g. admin, member)."]],["Assign role","assign-role",["Assign a role to an existing user in a tenant.","Required. Tenant UUID.","Required. User UUID (Supabase Auth).","Required. Role key.","Authorization (RBAC & ABAC)","Tenant context","Work orders"]]]},{url:"/work-orders",sections:[["Work orders",null,["Lists and gets work orders for the current tenant; create, transition status, complete, log time; list attachments and update attachment metadata. Set tenant context before calling these methods. ","End-user CMMS flows: request portal (submit and track my requests), SLA rules, acknowledgment, and breach views are covered in Request portal and SLA. Asset downtime (availability events) is under Asset downtime."]],["List work orders","list-work-orders",["List all work orders for the current tenant (from v_work_orders)."]],["Get by ID","get-by-id",["Fetch a single work order by ID."]],["Create work order","create-work-order",["Create a new work order. Returns the new work order UUID.","Required. Tenant UUID.","Required. Work order title.","Optional. Description.","Optional. Default medium. Priority key.","Optional. Maintenance type key.","Optional. Assignee user UUID.","Optional. Location UUID.","Optional. Asset UUID.","Optional. ISO date string.","Optional. PM schedule UUID.","Optional. Project UUID for cost roll-up by project. See Projects and Costs & lifecycle."]],["Transition status","transition-status",["Move a work order to a new status (e.g. from open to in_progress)."]],["Complete work order","complete-work-order",["Mark a work order as completed (transition to completed status). You can optionally record cause and resolution when completing."]],["Log time","log-time",["Log time spent on a work order. Returns the time entry UUID.","Required. Tenant UUID.","Required. Work order UUID.","Required. Number of minutes.","Optional. ISO date string.","Optional. User UUID. Defaults to current user.","Optional. Work description."]],["Attachments overview","attachments-overview",["Attachments use Supabase Storage and a database trigger: there is no RPC to “add” an attachment. You upload a file to the attachments bucket with path tenant_id/work_order/work_order_id/filename (three folder segments before the filename). A trigger creates app.files and app.entity_attachments. The SDK provides list attachments and update attachment metadata; use Storage for upload and signed URLs.","| Action | SDK / API |\n|--------|-----------|\n| Create attachment | client.supabase.storage.from('attachments').upload(path, file, opts). Path: tenant_id/work_order/work_order_id/uuid_filename; trigger creates records. |\n| List attachments | client.workOrders.listAttachments(workOrderId). Returns WorkOrderAttachmentRow[] with id, bucket_id, storage_path, filename, label, kind, etc. |\n| Get file URL | client.supabase.storage.from(row.bucket_id).createSignedUrl(row.storage_path, expiresIn). |\n| Update label/kind | client.workOrders.updateAttachmentMetadata({ attachmentId, label?, kind? }). |","Set tenant context with client.setTenant(tenantId) before listing or uploading."]],["Upload attachment","upload-attachment",["Upload the file to the attachments bucket. The path must be {tenantId}/work_order/{workOrderId}/{uuid}_{filename} (folder segments are tenant, entity type, entity id). Optional metadata (tenant_id, entity_type, entity_id, label, kind, document fields) may be passed if your Supabase version supports it; otherwise set label/kind later via rpc_update_entity_attachment_metadata.","The uploader must be a tenant member and either assigned to the work order or have workorder.edit permission; otherwise Storage RLS rejects the upload."]],["List attachments","list-attachments",["List attachments for a work order. Returns rows with id, work_order_id, file_id, bucket_id, storage_path, filename, label, kind, created_by_name, created_at. Use bucket_id and storage_path with createSignedUrl (see next section)."]],["Get signed URL","get-signed-url",["Attachments are stored in a private bucket. Do not store permanent URLs. For each row from listAttachments, call createSignedUrl with bucket_id and storage_path to get a short-lived URL (e.g. 1 hour). RLS on storage.objects is evaluated when creating the signed URL; only users who can read the linked work order receive a URL."]],["Update attachment metadata","update-attachment-metadata",["Set or change the label and/or kind after upload (e.g. when Storage metadata was not used). The caller must be a tenant member and either the attachment creator or an admin/manager. Get attachmentId from client.workOrders.listAttachments(workOrderId) (row id).","Required. Attachment UUID (row id from listAttachments).","Optional. Label. Max 255 characters.","Optional. Kind key (e.g. photo, document); format a-z0-9_.","Mobile field","Tenant context","Costs & lifecycle","Assets"]]]},{url:"/plugins/how-to-build",sections:[["How to build a plugin",null,["Build an integration or extension that runs outside the core database: your code calls the public API, and optionally receives signed outbound webhooks when audited data changes. This page is the checklist from zero to first delivery. For deeper behavior (payload shape, HMAC details, inbound allowlist), read Building plugins and the Plugins SDK reference. ","Plugins do not add tables or migrations in core. If you need new schema, that belongs in a first-party module, not a plugin."]],["What you are building","what-you-are-building",["At a high level:","A catalog row (int.plugins) so tenants can discover and install your integration.","Per-tenant installation with config (e.g. webhook_url) and optional secret_ref pointing at a Vault secret name used for HMAC.","Optional subscriptions so specific audit.entity_changes rows enqueue outbound HTTPS POSTs to your URL.","Your service: verify signatures, stay idempotent, then call views/RPCs or talk to external systems (SAP, Slack, etc.)."]],["Prerequisites","prerequisites",["Supabase project with this schema (or compatible deployment): Auth, Vault, pg_net, scheduled rpc_process_plugin_deliveries (e.g. pg_cron).","Backend that can call rpc_register_plugin with a key allowed for your environment (service role or equivalent—never from the browser).","HTTPS endpoint reachable from the database for outbound webhooks (local Docker often needs host.docker.internal or a tunnel). The database repo ships plugins/example—see plugins/example/README.md for a minimal receiver and smoke script.","Familiarity with Authentication, Tenant context, and Authorization—tenant admins install plugins; your receiver acts as its own integration."]],["1. Register in the catalog","1-register-in-the-catalog",["Pick a stable p_key: lowercase, a-z, 0-9, underscores only (^[a-z0-9_]+$), 2–80 characters. Register once from a trusted server (idempotent upsert):","Set p_is_integration: true when the plugin talks to an external system. See Building plugins — Register plugin for full context."]],["2. Store secrets in Vault","2-store-secrets-in-vault",["For outbound signing (and inbound verification), create a secret in Supabase Vault with a unique name (e.g. my_integration_hmac_prod). The plaintext is your shared HMAC key.","On the installation you set secret_ref to that name, not the secret value. The database resolves the secret when signing outbound requests and when verifying rpc_plugin_ingest_webhook."]],["3. Install for a tenant","3-install-for-a-tenant",["A user with tenant.admin (and correct tenant context) installs via the SDK:","config is JSON—use it for non-secret routing (API base URLs, feature flags). See Plugins — Install."]],["4. Configure outbound webhooks","4-configure-outbound-webhooks",["Outbound delivery POSTs JSON to config.webhook_url. Optional: timeout_ms, headers (non-secret only). The URL must be reachable from the Postgres host (Supabase: DB side / pg_net)."]],["5. Subscribe to entity changes","5-subscribe-to-entity-changes",["Nothing is sent until you create subscriptions for (table_schema, table_name) and operations (INSERT / UPDATE / DELETE). For UPDATE, use changed_fields_allowlist to filter noisy columns.","include_payload: false (default): snapshot carries record_id and changed_fields only—good for privacy and small payloads.","include_payload: true: includes old_data / new_data from audit—use only when you need full rows and accept PII/size risk.","Use client.plugins.upsertWebhookSubscription(...) as in Plugins — Webhook subscriptions."]],["6. Implement your HTTPS receiver","6-implement-your-https-receiver",["Your endpoint should:","Read the raw body bytes and verify X-Plugin-Signature (hex HMAC-SHA256 over the body) with the same plaintext as Vault—see Building plugins — Outbound webhooks.","Treat delivery as at-least-once: dedupe with X-Plugin-Delivery-Id and/or audit.id in the payload.","Respond with 2xx when the message is accepted for processing; non-2xx contributes to retries and eventual dead state.","Headers to expect include X-Plugin-Delivery-Id and X-Plugin-Event-Type."]],["7. Processing and retries","7-processing-and-retries",["The queue is drained by rpc_process_plugin_deliveries (typically every minute via pg_cron). You do not run a separate worker in-app: pg_net performs HTTP. Failed deliveries backoff and can land in dead after repeated failures—monitor client.plugins.listRecentDeliveries() or your ops stack."]],["8. Call the API and inbound webhooks","8-call-the-api-and-inbound-webhooks",["Reads/writes: Use public views (v_*) and RPCs (rpc_*) with appropriate JWTs—see Building plugins — Use the public API.","Inbound from partners: rpc_plugin_ingest_webhook verifies HMAC using the installation’s Vault secret; allowlisted actions are intentionally narrow—see Building plugins — Inbound webhooks."]],["9. Verify locally","9-verify-locally",["If you work in the database monorepo, use the plugins/example package: a minimal receiver plus pnpm smoke:setup to register example_receiver, seed Vault, create a tenant, subscribe to work_orders INSERT, enqueue a delivery, and run the processor. See that package’s README for WEBHOOK_SECRET, host.docker.internal, and env vars.","Building plugins (architecture)","Plugins SDK reference"]],["See also","see-also",["Building plugins — lifecycle, payload details, inbound allowlist","Plugins — client.plugins.* methods","Tenant context — required before tenant-scoped plugin APIs","Audit — where entity_changes come from"]]]}])for(let[a,s,r]of t)n.add({url:e+(s?"#"+s:""),title:a,content:[a,...r].join("\n"),pageTitle:s?t[0][0]:void 0});function s(e,t={}){let a=n.search(e,{...t,enrich:!0});return 0===a.length?[]:a[0].result.map(e=>({url:e.id,title:e.doc.title,pageTitle:e.doc.pageTitle}))}}}]);